INSERT INTO cms_trivia_packs (pack_id, label, description, color, question, options, answer_index, fact, sort_order) VALUES
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'Which is the longest bridge in Lagos?', '["Third Mainland Bridge","Carter Bridge","Eko Bridge","Lekki-Ikoyi Link Bridge"]'::jsonb, 0, 'At 11.8 km, Third Mainland Bridge was the longest in Africa when built in 1990.', 0),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'What year was Lagos State created?', '["1960","1967","1976","1991"]'::jsonb, 1, 'Lagos State was created on 27 May 1967 from the former Western Region.', 1),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'What is the popular yellow commercial bus in Lagos called?', '["Keke","Okada","Danfo","Molue"]'::jsonb, 2, 'Danfo buses carry over 10 million Lagosians daily.', 2),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'Which of these is NOT an LGA in Lagos State?', '["Ikeja","Surulere","Ogbomoso","Epe"]'::jsonb, 2, 'Ogbomoso is in Oyo State. Lagos has 20 LGAs.', 3),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'What is the famous arts market in Lekki called?', '["Balogun Market","Lekki Arts & Crafts Market","Tejuosho Market","Computer Village"]'::jsonb, 1, 'Lekki Arts & Crafts Market is Lagos''s top destination for souvenirs and local art.', 4),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'What does "CMS" stand for in Lagos bus stop name?', '["Central Motor Services","Church Missionary Society","City Municipal Services","Central Market Street"]'::jsonb, 1, 'The Church Missionary Society arrived in Lagos in 1842.', 5),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'Which is Africa''s largest open-air electronics market?', '["Trade Fair Complex","Computer Village, Ikeja","Alaba International","Ladipo Market"]'::jsonb, 1, 'Computer Village generates ₦1.5 billion daily with over 5,000 shops.', 6),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'Which bridge links Lagos Mainland to Lagos Island?', '["Third Mainland only","Carter Bridge only","Eko Bridge only","All three bridges"]'::jsonb, 3, 'Three bridges serve as links — Third Mainland (11.8 km), Carter (1901), and Eko (1975).', 7),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'Oshodi was famously called the most dangerous bus stop in which continent?', '["The World","Africa","West Africa","Nigeria"]'::jsonb, 1, 'Before Fashola''s 2009 cleanup, Oshodi had 500,000+ daily commuters and rampant crime.', 8),
('lagos', '🌊 Lagos Life', 'Bridges, buses, markets & neighborhoods', '#0ea5e9', 'What is "Agbado" known for among Lagos commuters?', '["Last affordable bus stop","Fastest BRT route","The end of Lagos","Cheapest fuel station"]'::jsonb, 2, '"Agbado is the end of Lagos" — it marks where Lagos meets Ogun State.', 9),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'In what year did Nigeria gain independence?', '["1955","1960","1963","1970"]'::jsonb, 1, 'Nigeria gained independence from Britain on 1 October 1960.', 100),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Which rock formation appears on the ₦100 note?', '["Olumo Rock","Aso Rock","Zuma Rock","Idanre Hills"]'::jsonb, 2, 'Zuma Rock stands 725m high — "Gateway to Abuja".', 101),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'What does FESTAC stand for?', '["Federal State Arts Council","Festival of Arts & Culture","Festival of African Culture","Federal Arts Commission"]'::jsonb, 1, 'FESTAC 77 attracted 17,000 participants from 59 countries to Lagos.', 102),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Which city is Nigeria''s seat of government?', '["Lagos","Kano","Ibadan","Abuja"]'::jsonb, 3, 'Abuja became the capital in 1991, replacing Lagos for neutrality.', 103),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Which Nigerian author won the Nobel Prize for Literature?', '["Chinua Achebe","Wole Soyinka","Ben Okri","Chimamanda Adichie"]'::jsonb, 1, 'Wole Soyinka won in 1986, the first African to receive the Nobel Prize in Literature.', 104),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'What is Nigeria''s national animal?', '["Lion","Elephant","Eagle","Horse"]'::jsonb, 2, 'The Eagle on the coat of arms represents strength.', 105),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Which state produces most of Nigeria''s cocoa?', '["Oyo","Ondo","Osun","Ekiti"]'::jsonb, 1, 'Ondo State accounts for over 40% of Nigeria''s cocoa production.', 106),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Who was Nigeria''s first military head of state?', '["Yakubu Gowon","Nnamdi Azikiwe","Tafawa Balewa","Aguiyi-Ironsi"]'::jsonb, 3, 'Aguiyi-Ironsi became head of state after the January 1966 coup.', 107),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'What is the Niger-Delta region primarily known for?', '["Agriculture","Oil production","Tin mining","Cocoa farming"]'::jsonb, 1, 'Nigeria is Africa''s largest oil producer with 35+ billion barrels in the Niger Delta.', 108),
('nigeria', '🇳🇬 Nigeria Essentials', 'History, landmarks & national icons', '#22c55e', 'Olumo Rock is located in which city?', '["Ibadan","Ijebu-Ode","Abeokuta","Osogbo"]'::jsonb, 2, 'Olumo Rock in Abeokuta served as a natural fortress during 19th century inter-tribal wars.', 109),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'Which dish is Ewa Agoyin typically paired with?', '["Rice","Agege Bread","Pounded Yam","Eba"]'::jsonb, 1, 'Ewa Agoyin + Agege Bread is Lagos''s most iconic street breakfast.', 200),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'The Eyo Festival masquerade is unique to which city?', '["Ibadan","Abeokuta","Lagos","Benin City"]'::jsonb, 2, 'The Eyo Festival features white-robed masquerades parading through Lagos Island.', 201),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'What Afrobeats artist made "Ojuelegba" globally famous?', '["Davido","Burna Boy","Wizkid","Fela Kuti"]'::jsonb, 2, 'Wizkid''s "Ojuelegba" was remixed by Drake and Skepta, making it an international hit.', 202),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'Which Nigerian musician is called "Abami Eda"?', '["Wizkid","Burna Boy","Fela Kuti","2Baba"]'::jsonb, 2, '"Abami Eda" (peculiar being) was Fela Kuti''s nickname. His Afrobeat was deeply political.', 203),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'What does "Omo, e choke!" mean in Lagos slang?', '["It is expensive","It is amazing","I am tired","It is crowded"]'::jsonb, 1, '"E choke" was popularized by Davido and means something is absolutely amazing.', 204),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'What is "Okrika" in Lagos markets?', '["Stolen goods","Second-hand clothes","Fake designer bags","Cheap local fabric"]'::jsonb, 1, '"Bend-down-select" Okrika clothes arrive in bales from Europe.', 205),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'The Lisabi Festival celebrates which historical event?', '["Founding of Lagos","Egba liberation from Oyo","Fall of Benin Empire","Battle of Abeokuta"]'::jsonb, 1, 'Lisabi Agbongbo Akala led the Egba revolt against Oyo around 1775.', 206),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'Which slang means "it is finished" in Lagos pidgin?', '["\"E don be\"","\"Ko si\"","\"Sharp-sharp\"","\"Agbero\""]'::jsonb, 0, '"E don be" is the universal Lagos phrase for something completely finished or sold out.', 207),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'What Yoruba word became universal Lagos friend slang?', '["Aburo","Omo","Olorun","Baba"]'::jsonb, 1, '"Omo" (meaning child) became a universal term of address across ethnic groups in Lagos.', 208),
('culture', '🎭 Culture & Vibes', 'Food, music, slang & festivals', '#f97316', 'Which beach is only accessible by boat in Lagos?', '["Elegushi Beach","Tarkwa Bay","Lekki Beach","Oniru Beach"]'::jsonb, 1, 'Tarkwa Bay is a sheltered beach near the harbour with no road access — boats only.', 209);
