('hausa', '🕌 Hausa Words', 'Basic Hausa vocabulary', '#f97316', 5, '[{"num":1,"text":"Hausa for \"welcome\"","answer":"SANNU","row":0,"col":0},{"num":3,"text":"Hausa for \"market\"","answer":"KASUWA","row":2,"col":0}]'::jsonb, '[{"num":1,"text":"Hausa for \"king\" (Sarki)","answer":"SARKI","row":0,"col":0},{"num":2,"text":"Hausa for \"water\"","answer":"RUWA","row":0,"col":3}]'::jsonb, 12),
('landmarks', '🏗️ Landmarks', 'Famous Nigerian structures', '#64748b', 5, '[{"num":1,"text":"Rock housing the Presidential Villa","answer":"ASO","row":0,"col":0},{"num":3,"text":"Gateway rock on Abuja highway","answer":"ZUMA","row":2,"col":0}]'::jsonb, '[{"num":1,"text":"Abeokuta rock fortress","answer":"OLUMO","row":0,"col":0},{"num":2,"text":"Sacred grove in Osun State","answer":"OSUN","row":0,"col":2}]'::jsonb, 13),
('transport', '🚐 Transport', 'Getting around Nigeria', '#eab308', 5, '[{"num":1,"text":"Yellow Lagos bus (VW T3)","answer":"DANFO","row":0,"col":0},{"num":3,"text":"Three-wheeled taxi","answer":"KEKE","row":2,"col":0}]'::jsonb, '[{"num":1,"text":"Motorbike taxi (banned in Lagos)","answer":"OKADA","row":0,"col":0},{"num":2,"text":"Lagos rapid transit bus","answer":"BRT","row":0,"col":3}]'::jsonb, 14),
