INSERT INTO cms_campaign (chapter_id, week, title, subtitle, icon, color, badge, badge_emoji, intro, category_filter, question_count, stages, facts, sort_order) VALUES
('ch-1', 1, 'Learn the 20 LGAs', 'Master every Local Government Area', '🏛️', '#00ff88', 'lga-master', '🏛️', 'Lagos is divided into 20 Local Government Areas, each with its own character. From the bustling streets of Mushin to the elite enclaves of Eti-Osa, can you locate them all?', 'lgas', 10, '[{"id":1,"name":"Lagos Island","questions":3,"stars":0},{"id":2,"name":"Mainland Core","questions":3,"stars":0},{"id":3,"name":"Ikeja Corridor","questions":3,"stars":0},{"id":4,"name":"Final Exam","questions":5,"stars":0}]'::jsonb, '["Lagos had just 5 LGAs in 1967 — it now has 20 plus 37 LCDAs.","Eti-Osa (Victoria Island, Lekki, Ikoyi) generates more tax revenue than 30 Nigerian states combined.","Ajeromi-Ifelodun has the highest population density in Lagos at over 100,000 per km²."]'::jsonb, 0),
('ch-2', 2, 'Master the Markets', 'From Balogun to Alaba International', '🛒', '#fbbf24', 'market-master', '🛒', 'Lagos markets are the beating heart of West African commerce. Over ₦10 billion changes hands daily across hundreds of markets. Can you pinpoint where the trade happens?', 'markets', 10, '[{"id":1,"name":"Island Markets","questions":3,"stars":0},{"id":2,"name":"Mainland Markets","questions":3,"stars":0},{"id":3,"name":"Specialty Markets","questions":3,"stars":0},{"id":4,"name":"Market Master","questions":5,"stars":0}]'::jsonb, '["Alaba International Market generates over ₦3 billion daily in electronics trade.","Balogun Market on Lagos Island is the largest textile market in West Africa.","Mile 12 receives over 15,000 tonnes of food daily from across Nigeria."]'::jsonb, 1),
('ch-3', 3, 'Bridge the Gaps', 'Transport links that connect Lagos', '🌉', '#00d4ff', 'bridge-master', '🌉', 'Lagos is a city of water. Islands, lagoons, and creeks divide it — but bridges, ferries, and expressways stitch it together. How well do you know the arteries of Africa''s largest city?', 'transport', 10, '[{"id":1,"name":"The Bridges","questions":3,"stars":0},{"id":2,"name":"Bus Terminals","questions":3,"stars":0},{"id":3,"name":"Rail & Water","questions":3,"stars":0},{"id":4,"name":"Transport Expert","questions":5,"stars":0}]'::jsonb, '["Third Mainland Bridge (11.8 km) was Africa''s longest bridge when completed in 1990.","Over 10 million people use Lagos public transport daily.","The Blue Line rail (Iddo-Mile 2) opened in 2023 — Lagos'' first modern rail."]'::jsonb, 2),
('ch-4', 4, 'Cultural Lagos', 'Heritage, arts, and history', '🎭', '#a855f7', 'culture-master', '🎭', 'From the slave ports of Badagry to the Afrobeat shrines of Ikeja, Lagos is a cultural powerhouse. Eyo masquerades, Brazilian Quarter architecture, and world-class galleries await.', 'culture', 10, '[{"id":1,"name":"Heritage Sites","questions":3,"stars":0},{"id":2,"name":"Art & Music","questions":3,"stars":0},{"id":3,"name":"Historical Roots","questions":3,"stars":0},{"id":4,"name":"Culture Legend","questions":5,"stars":0}]'::jsonb, '["The Eyo Festival dates back to the early 1800s — white-robed masquerades dance through Lagos Island.","Nike Art Gallery has over 8,000 artworks — the largest private collection in West Africa.","Fela Kuti''s Kalakuta Republic was raided by 1,000 soldiers in 1977."]'::jsonb, 3);
INSERT INTO cms_coloring (scene_id, title, description, color, min_parts, parts, guide, svg_key, sort_order) VALUES
('danfo', '🚐 Danfo Bus', 'Color the iconic Lagos yellow bus', '#fde047', 4, '["body","bumper","window1","window2","window3","stripe","wheel1","wheel2","headlight"]'::jsonb, '{"body":"#fde047","bumper":"#1e293b","window1":"#64748b","window2":"#64748b","window3":"#64748b","stripe":"#1e293b","wheel1":"#1e293b","wheel2":"#1e293b","headlight":"#fde047"}'::jsonb, 'danfo', -3),
