('keke', '🛺 Keke Napep', 'Color the Lagos tricycle taxi', '#fde047', 3, '["body","roof","window1","window2","wheel1","wheel2","cargo","wheel3"]'::jsonb, '{"body":"#fde047","roof":"#22c55e","window1":"#64748b","window2":"#64748b","wheel1":"#1e293b","wheel2":"#1e293b","cargo":"#f97316","wheel3":"#1e293b"}'::jsonb, 'keke', 0),
