('church', '⛪ Lagos Church', 'Paint a classic Nigerian church', '#3b82f6', 3, '["wall","roof","door","window1","window2","cross","ground"]'::jsonb, '{"wall":"#ffffff","roof":"#ef4444","door":"#a16207","window1":"#3b82f6","window2":"#3b82f6","cross":"#fde047","ground":"#22c55e"}'::jsonb, 'church', 2),
('palm', '🌴 Palm Tree', 'Color a tropical palm tree', '#22c55e', 3, '["trunk","leaf1","leaf2","leaf3","coconut1","coconut2","ground"]'::jsonb, '{"trunk":"#a16207","leaf1":"#22c55e","leaf2":"#22c55e","leaf3":"#22c55e","coconut1":"#a16207","coconut2":"#a16207","ground":"#fde047"}'::jsonb, 'palm', 3),
('jollof', '🍚 Jollof Rice Pot', 'Color the famous jollof pot', '#ef4444', 3, '["pot","potbody","rice","base","handle","lid","steam1","steam2"]'::jsonb, '{"pot":"#64748b","potbody":"#64748b","rice":"#ef4444","base":"#1e293b","handle":"#64748b","lid":"#64748b","steam1":"#ffffff","steam2":"#ffffff"}'::jsonb, 'jollof', 4),
('boat', '🚣 Fishing Boat', 'Color a Lagos lagoon boat', '#0ea5e9', 3, '["hull","mast","sail","water","deck","sun"]'::jsonb, '{"hull":"#a16207","mast":"#a16207","sail":"#ffffff","water":"#3b82f6","deck":"#a16207","sun":"#fde047"}'::jsonb, 'boat', 5),
('agbada', '👘 Agbada Outfit', 'Design a traditional outfit', '#a855f7', 3, '["head","agbada","inner","leg1","leg2","cap"]'::jsonb, '{"head":"#a16207","agbada":"#a855f7","inner":"#ffffff","leg1":"#1e293b","leg2":"#1e293b","cap":"#a855f7"}'::jsonb, 'agbada', 6),
('fuel', '⛽ Fuel Station', 'Paint a Lagos petrol station', '#ef4444', 3, '["building","awning","pump1","pump2","ground","sign"]'::jsonb, '{"building":"#ffffff","awning":"#ef4444","pump1":"#22c55e","pump2":"#22c55e","ground":"#64748b","sign":"#fde047"}'::jsonb, 'fuel', 7),
('suya', '🥩 Suya Stand', 'Color the suya man''s grill', '#f97316', 3, '["grill","roof","skewers","meat1","meat2","meat3","ground","smoke"]'::jsonb, '{"grill":"#64748b","roof":"#a16207","skewers":"#64748b","meat1":"#a16207","meat2":"#a16207","meat3":"#a16207","ground":"#64748b","smoke":"#ffffff"}'::jsonb, 'suya', 8),
('skyline', '🏙️ Lagos Skyline', 'Paint the city skyline', '#3b82f6', 4, '["bldg1","bldg2","bldg3","bldg4","bldg5","bldg6","ground","sun"]'::jsonb, '{"bldg1":"#64748b","bldg2":"#3b82f6","bldg3":"#0ea5e9","bldg4":"#a855f7","bldg5":"#f97316","bldg6":"#22c55e","ground":"#1e293b","sun":"#fde047"}'::jsonb, 'skyline', 9),
('okada', '🏍️ Okada Bike', 'Color a motorcycle taxi', '#ef4444', 3, '["fwheel","rwheel","frame","seat","tank","handlebar"]'::jsonb, '{"fwheel":"#1e293b","rwheel":"#1e293b","frame":"#ef4444","seat":"#1e293b","tank":"#ef4444","handlebar":"#64748b"}'::jsonb, 'okada', 10);
INSERT INTO cms_adventures (story_id, title, description, color, start_node, nodes, sort_order) VALUES
('commute', '🚌 Lagos Commute', 'Survive the morning rush from Ikeja to VI', '#eab308', 's', '{"s":{"text":"7AM Monday. You need to get from Ikeja to VI for a 9AM interview.","choices":[{"text":"🚌 Take BRT","next":"brt","health":-10,"xp":10},{"text":"🚐 Take Danfo","next":"danfo","health":-20,"xp":20},{"text":"🚗 Order Uber","next":"uber","health":0,"xp":5}]},"brt":{"text":"BRT is packed. Bus breaks down at Maryland!","choices":[{"text":"⏳ Wait for rescue","next":"wait","health":-10,"xp":10},{"text":"🏍️ Find an Okada","next":"okada","health":-20,"xp":30}]},"danfo":{"text":"Driver speeds like F1. Massive pothole on Third Mainland Bridge!","choices":[{"text":"🙏 Hold tight","next":"bridge","health":-30,"xp":40},{"text":"😤 Complain","next":"fight","health":-40,"xp":10}]},"uber":{"text":"Driver: ''I''m at the junction, can you walk down?''","choices":[{"text":"🚶 Walk down","next":"walk","health":-15,"xp":10},{"text":"❌ Cancel, take Danfo","next":"danfo","health":-10,"xp":10}]},"wait":{"text":"45 min later rescue arrives. You reach VI at 9:30 — late but HR is also stuck!","choices":[{"text":"🏢 Enter office","next":"end_win","health":0,"xp":50}]},"okada":{"text":"Okada rider dodges trailers. Heart in mouth, you arrive at 8:45!","choices":[{"text":"💰 Pay and enter","next":"end_win","health":-20,"xp":100}]},"bridge":{"text":"Danfo survives! LASTMA flags driver down.","choices":[{"text":"🙏 Beg officer","next":"beg","health":-10,"xp":20},{"text":"🚶 Drop and walk","next":"walk","health":-30,"xp":10}]},"fight":{"text":"Driver parks. ''Everybody come down!'' Stranded on bridge.","choices":[{"text":"😔 Admit defeat","next":"end_lose","health":-50,"xp":0}]},"walk":{"text":"Scorching sun. You arrive sweating through interview clothes.","choices":[{"text":"😰 Enter","next":"end_lose","health":-60,"xp":10}]},"beg":{"text":"LASTMA takes pity. Bus released, you arrive 8:55!","choices":[{"text":"🏢 Enter","next":"end_win","health":0,"xp":150}]}}'::jsonb, 0),
('market', '🛒 Balogun Market', 'Navigate Lagos'' largest market', '#f97316', 's', '{"s":{"text":"Entrance of Balogun Market. You need wedding fabric.","choices":[{"text":"🗺️ Ask trader","next":"ask","health":0,"xp":20},{"text":"🚶 Explore alone","next":"lost","health":-10,"xp":10},{"text":"📱 Use Maps","next":"maps","health":0,"xp":5}]},"ask":{"text":"Iya Alagbo guides you but quotes 3x market price.","choices":[{"text":"💰 Pay her","next":"overpay","health":0,"xp":10},{"text":"🤝 Negotiate","next":"negotiate","health":0,"xp":40},{"text":"🏃 Decline","next":"lost","health":-10,"xp":20}]},"lost":{"text":"40 min later you''re lost. Phone at 5%.","choices":[{"text":"🆘 Ask for help","next":"help","health":-20,"xp":20},{"text":"📵 Retrace steps","next":"retrace","health":-30,"xp":10}]},"maps":{"text":"Maps shows one big blob. Data runs out.","choices":[{"text":"🤷 Ask someone","next":"help","health":-10,"xp":15},{"text":"🚗 Head to entrance","next":"negotiate","health":0,"xp":20}]},"negotiate":{"text":"15 min of hard bargaining. Beautiful Ankara at fair price + free headwrap!","choices":[{"text":"🛍️ Purchase","next":"end_win","health":0,"xp":120}]},"overpay":{"text":"Paid full price but quality fabric. Trader adds you on WhatsApp.","choices":[{"text":"📱 Save number","next":"end_win","health":0,"xp":50}]},"help":{"text":"Boy offers to guide you for ₦500. 5 min later you''re there!","choices":[{"text":"💵 Pay and shop","next":"negotiate","health":0,"xp":80}]},"retrace":{"text":"Wander an hour. Phone dies. Exit on wrong street.","choices":[{"text":"😞 Head home","next":"end_lose","health":-40,"xp":0}]}}'::jsonb, 1),
('beach', '🏖️ Lagos Beach Day', 'Plan the perfect beach day', '#0ea5e9', 's', '{"s":{"text":"Saturday beach day! Which beach?","choices":[{"text":"⛵ Tarkwa Bay","next":"tarkwa","health":0,"xp":30},{"text":"🏖️ Elegushi","next":"elegushi","health":0,"xp":20},{"text":"🌊 Lekki Beach","next":"lekki","health":0,"xp":10}]},"tarkwa":{"text":"Boat to Tarkwa costs ₦2000. Sea breeze is incredible.","choices":[{"text":"🐎 Horse riding","next":"horse","health":0,"xp":50},{"text":"🏊 Swim","next":"swim","health":0,"xp":80}]},"elegushi":{"text":"Lively! Music, food. A wave soaks your phone!","choices":[{"text":"😂 Laugh it off","next":"swim","health":-10,"xp":60},{"text":"😡 Panic","next":"panic","health":-20,"xp":20}]},"lekki":{"text":"Free but crowded. Vendor won''t stop selling suya.","choices":[{"text":"🥜 Buy suya","next":"suya","health":0,"xp":40},{"text":"😤 Send away","next":"vendor","health":-10,"xp":20}]},"horse":{"text":"Horse ride at sunset is magical. Photos go viral!","choices":[{"text":"📸 Head home","next":"end_win","health":0,"xp":150}]},"swim":{"text":"Best day ever. Sunset, cold drinks, great company!","choices":[{"text":"🌅 Head home","next":"end_win","health":0,"xp":120}]},"suya":{"text":"Vendor''s pepper suya is amazing. You buy more!","choices":[{"text":"🌅 Head home","next":"end_win","health":0,"xp":80}]},"panic":{"text":"Spent beach day panicking about phone.","choices":[{"text":"😕 Pack up","next":"end_lose","health":-20,"xp":20}]},"vendor":{"text":"Vendor argues loudly. Whole beach watching. Embarrassed.","choices":[{"text":"😖 Retreat","next":"end_lose","health":-30,"xp":0}]}}'::jsonb, 2),
('owambe', '🎉 Owambe Party', 'Survive a Lagos society wedding', '#ec4899', 's', '{"s":{"text":"You''re invited to an owambe in Lekki. The aso-ebi costs ₦50,000!","choices":[{"text":"💰 Buy aso-ebi","next":"aso","health":0,"xp":20},{"text":"👔 Wear own outfit","next":"own","health":-10,"xp":10},{"text":"❌ Skip it","next":"skip","health":-5,"xp":5}]},"aso":{"text":"You look stunning! The party jollof is legendary.","choices":[{"text":"🍚 Eat jollof","next":"jollof","health":0,"xp":40},{"text":"💃 Hit dance floor","next":"dance","health":0,"xp":50}]},"own":{"text":"People give you looks but the DJ is 🔥","choices":[{"text":"💃 Dance anyway","next":"dance","health":0,"xp":30},{"text":"📸 Take photos","next":"photos","health":0,"xp":20}]},"skip":{"text":"You stay home scrolling Instagram. Everyone''s posts look amazing.","choices":[{"text":"😔 Regret","next":"end_lose","health":-20,"xp":0}]},"jollof":{"text":"Party jollof hits different! Meat is premium. You go for 3rd plate.","choices":[{"text":"💃 Dance it off","next":"dance","health":0,"xp":60}]},"dance":{"text":"You''re killing it! Someone records and it goes viral on TikTok!","choices":[{"text":"🌟 Enjoy fame","next":"end_win","health":0,"xp":150}]},"photos":{"text":"Your photos are fire. The couple asks you to be official photographer!","choices":[{"text":"📸 Accept","next":"end_win","health":0,"xp":100}]}}'::jsonb, 3),
('nepa', '⚡ NEPA Wahala', 'Survive a 3-day power outage in Lagos', '#f59e0b', 's', '{"s":{"text":"Power''s been out 3 days. Phone at 2%. Fridge items spoiling.","choices":[{"text":"⛽ Buy fuel for gen","next":"fuel","health":-20,"xp":20},{"text":"🔋 Find charging spot","next":"charge","health":0,"xp":15},{"text":"🕯️ Use candle","next":"candle","health":-10,"xp":10}]},"fuel":{"text":"Fuel queue at Oando is 2 hours long. Sun is blazing.","choices":[{"text":"⏳ Wait in line","next":"wait_fuel","health":-20,"xp":30},{"text":"🏃 Try black market","next":"black","health":-10,"xp":40}]},"charge":{"text":"You find a POS agent with solar power who charges ₦200 per phone.","choices":[{"text":"🔌 Charge phone","next":"charged","health":0,"xp":30},{"text":"🏠 Go home","next":"candle","health":-10,"xp":10}]},"candle":{"text":"Reading by candlelight. Mosquitoes attack. No fan.","choices":[{"text":"🦟 Endure it","next":"end_lose","health":-40,"xp":10}]},"wait_fuel":{"text":"Finally got fuel! Generator roars to life. Neighbors come begging.","choices":[{"text":"🤝 Share power","next":"end_win","health":0,"xp":100}]},"black":{"text":"Black market fuel is ₦800/litre but available instantly.","choices":[{"text":"💰 Pay up","next":"end_win","health":-10,"xp":80}]},"charged":{"text":"Phone charged! You order food on Bolt Food before it dies again.","choices":[{"text":"🍔 Enjoy food","next":"end_win","health":0,"xp":60}]}}'::jsonb, 4),
('rain', '🌧️ Rainy Season', 'Navigate Lagos flooding', '#6366f1', 's', '{"s":{"text":"Heavy rain since 4AM. Your street is flooded knee-deep.","choices":[{"text":"🚗 Drive through","next":"drive","health":-30,"xp":20},{"text":"🏠 Work from home","next":"wfh","health":0,"xp":10},{"text":"🚶 Wade through","next":"wade","health":-20,"xp":30}]},"drive":{"text":"Car stalls in flood water at Lekki-Epe Expressway!","choices":[{"text":"🆘 Call mechanic","next":"mechanic","health":-20,"xp":20},{"text":"🚶 Abandon car","next":"wade","health":-30,"xp":10}]},"wfh":{"text":"Internet is down too. Boss calls — urgent meeting at the office.","choices":[{"text":"🚶 Wade to bus stop","next":"wade","health":-20,"xp":20},{"text":"📱 Zoom from phone","next":"zoom","health":0,"xp":40}]},"wade":{"text":"Water is murky. Something brushes your leg. You pray it''s not a snake.","choices":[{"text":"🏃 Run!","next":"run","health":-10,"xp":50},{"text":"🙏 Walk carefully","next":"careful","health":0,"xp":30}]},"mechanic":{"text":"Mechanic says ₦80,000 to fix. Your savings cry.","choices":[{"text":"💰 Pay","next":"end_win","health":-10,"xp":50}]},"zoom":{"text":"You lead the meeting from your bedroom. Boss is impressed!","choices":[{"text":"💪 Boss mode","next":"end_win","health":0,"xp":120}]},"run":{"text":"You sprint to higher ground. Made it safely! A true Lagosian.","choices":[{"text":"😅 Dry off","next":"end_win","health":0,"xp":100}]},"careful":{"text":"You make it through. Your shoes are ruined but you''re alive.","choices":[{"text":"👟 Buy new shoes","next":"end_win","health":-10,"xp":60}]}}'::jsonb, 5),
('traffic', '🚗 Lagos Traffic', 'Escape the worst go-slow ever', '#ef4444', 's', '{"s":{"text":"You''ve been stuck on Lekki-Epe for 2 hours. Not moving.","choices":[{"text":"🏍️ Take Okada","next":"okada","health":-20,"xp":40},{"text":"🚶 Walk","next":"walk","health":-15,"xp":20},{"text":"📱 Order food to car","next":"food","health":0,"xp":30}]},"okada":{"text":"Okada weaves through. Terrifying but effective.","choices":[{"text":"🙏 Hold on","next":"arrive","health":-10,"xp":80}]},"walk":{"text":"Walking in Lagos heat. You pass 200 cars. People envy you.","choices":[{"text":"💪 Keep going","next":"arrive","health":-20,"xp":50}]},"food":{"text":"Shawarma guy on bike delivers to your window. Lagos innovation!","choices":[{"text":"🍔 Eat and wait","next":"wait","health":0,"xp":40}]},"arrive":{"text":"You finally arrive! 3 hours for a 30-minute journey. Classic Lagos.","choices":[{"text":"😅 Made it","next":"end_win","health":0,"xp":100}]},"wait":{"text":"Traffic clears at 9PM. You get home by 10PM.","choices":[{"text":"😴 Sleep","next":"end_win","health":0,"xp":60}]}}'::jsonb, 6),
('suya', '🥩 Suya Hunt', 'Find the best suya in Lagos', '#d97706', 's', '{"s":{"text":"It''s 10PM. Suya craving hits hard. Where to go?","choices":[{"text":"🔥 Yaba suya spot","next":"yaba","health":0,"xp":30},{"text":"🔥 VI suya joint","next":"vi","health":0,"xp":20},{"text":"🔥 Obalende corner","next":"obalende","health":0,"xp":40}]},"yaba":{"text":"Mallam Ibrahim''s suya is legendary. Queue is 30 minutes.","choices":[{"text":"⏳ Wait","next":"yaba_wait","health":0,"xp":50},{"text":"🏃 Try elsewhere","next":"obalende","health":0,"xp":20}]},"vi":{"text":"Upscale suya spot. ₦5000 per wrap but presentation is 🔥","choices":[{"text":"💰 Buy it","next":"vi_eat","health":0,"xp":40},{"text":"😤 Too expensive","next":"obalende","health":0,"xp":20}]},"obalende":{"text":"Underground suya king. No signboard, just smoke and aroma.","choices":[{"text":"🥩 Order special","next":"special","health":0,"xp":60}]},"yaba_wait":{"text":"Worth every minute. Perfectly spiced, onions and tomato on point!","choices":[{"text":"😋 Enjoy","next":"end_win","health":0,"xp":120}]},"vi_eat":{"text":"Instagram-worthy. Tastes good but your wallet weeps.","choices":[{"text":"📸 Post it","next":"end_win","health":0,"xp":80}]},"special":{"text":"The best suya you''ve ever tasted. Secret pepper mix is unreal!","choices":[{"text":"🔥 Order more","next":"end_win","health":0,"xp":150}]}}'::jsonb, 7),
('house', '🏠 House Hunting', 'Find affordable rent in Lagos', '#8b5cf6', 's', '{"s":{"text":"Your rent expires next month. Budget: ₦800K/year. Where to look?","choices":[{"text":"🏘️ Yaba","next":"yaba","health":0,"xp":20},{"text":"🏘️ Lekki Phase 1","next":"lekki","health":-10,"xp":10},{"text":"🏘️ Gbagada","next":"gbagada","health":0,"xp":30}]},"yaba":{"text":"Agent shows a self-con near UNILAG. ₦700K but no water.","choices":[{"text":"💧 Negotiate water","next":"negotiate","health":0,"xp":40},{"text":"👀 Keep looking","next":"gbagada","health":0,"xp":20}]},"lekki":{"text":"₦2.5 million minimum! Agent laughs at your budget.","choices":[{"text":"😤 Leave","next":"gbagada","health":-10,"xp":10}]},"gbagada":{"text":"Nice 2-bedroom for ₦900K. Slightly over budget but spacious.","choices":[{"text":"🤝 Negotiate down","next":"negotiate","health":0,"xp":50},{"text":"✅ Take it","next":"take","health":0,"xp":30}]},"negotiate":{"text":"Landlord agrees to ₦750K! You did the Lagos hustle right.","choices":[{"text":"✅ Sign","next":"end_win","health":0,"xp":150}]},"take":{"text":"You move in. Neighbors are friendly. Generator works!","choices":[{"text":"🏠 Settle in","next":"end_win","health":0,"xp":100}]}}'::jsonb, 8),
('nysc', '🎓 NYSC Camp', 'Survive orientation camp', '#22c55e', 's', '{"s":{"text":"Welcome to NYSC camp in Iyana-Ipaja! 3 weeks of drills await.","choices":[{"text":"💪 Embrace it","next":"drill","health":0,"xp":30},{"text":"😩 Complain","next":"complain","health":-20,"xp":10},{"text":"🤝 Make friends","next":"friends","health":0,"xp":40}]},"drill":{"text":"4:30AM parade. Soldier screams. You do 50 pushups.","choices":[{"text":"💪 Push through","next":"strong","health":0,"xp":50},{"text":"🤕 Fake injury","next":"fake","health":-10,"xp":20}]},"complain":{"text":"Platoon leader hears you. Extra punishment drills!","choices":[{"text":"💪 Endure","next":"strong","health":-20,"xp":40}]},"friends":{"text":"You meet people from all 36 states. A guy from Kano teaches you Hausa.","choices":[{"text":"🗣️ Learn more","next":"strong","health":0,"xp":60}]},"strong":{"text":"You become platoon leader! Everyone respects you.","choices":[{"text":"🎖️ Graduate","next":"end_win","health":0,"xp":150}]},"fake":{"text":"Doctor sees through it. More pushups as punishment.","choices":[{"text":"😅 Just do it","next":"end_win","health":-20,"xp":80}]}}'::jsonb, 9),
('date', '💕 First Date', 'Navigate a Lagos first date', '#f472b6', 's', '{"s":{"text":"First date tonight! Where do you take them?","choices":[{"text":"🍽️ Terra Kulture, VI","next":"terra","health":0,"xp":30},{"text":"🎬 Genesis Cinema","next":"cinema","health":0,"xp":20},{"text":"🌊 Nike Art Gallery","next":"nike","health":0,"xp":40}]},"terra":{"text":"Classy choice! Live music playing. Menu is pricey though.","choices":[{"text":"💰 Order everything","next":"order","health":0,"xp":50},{"text":"🥗 Share a platter","next":"share","health":0,"xp":40}]},"cinema":{"text":"Nollywood premiere! Popcorn for two. Very romantic.","choices":[{"text":"🎬 Enjoy film","next":"enjoy","health":0,"xp":40}]},"nike":{"text":"They love art! You walk through 5 floors discussing pieces.","choices":[{"text":"🎨 Buy them art","next":"buy","health":0,"xp":60}]},"order":{"text":"Bill is ₦45,000. Your card declines. MobilePay saves you!","choices":[{"text":"😅 Laugh about it","next":"end_win","health":0,"xp":100}]},"share":{"text":"Great conversation over food. You exchange playlists!","choices":[{"text":"🎵 Walk on beach","next":"end_win","health":0,"xp":120}]},"enjoy":{"text":"You both cry at the Nollywood drama. Connection!","choices":[{"text":"💕 Plan date 2","next":"end_win","health":0,"xp":100}]},"buy":{"text":"You buy them a Yoruba bronze piece. They''re speechless!","choices":[{"text":"💕 Best date ever","next":"end_win","health":0,"xp":150}]}}'::jsonb, 10),
('island', '🏝️ Island Hopping', 'Explore Lagos islands', '#14b8a6', 's', '{"s":{"text":"You discover Lagos has hidden islands. Which first?","choices":[{"text":"🏝️ Tarkwa Bay","next":"tarkwa","health":0,"xp":30},{"text":"🏝️ Snake Island","next":"snake","health":0,"xp":40},{"text":"🏝️ Banana Island","next":"banana","health":0,"xp":20}]},"tarkwa":{"text":"Boat ride from Maroko. Crystal clear water!","choices":[{"text":"🏊 Swim","next":"swim","health":0,"xp":50},{"text":"🐎 Ride horses","next":"horse","health":0,"xp":60}]},"snake":{"text":"Mangrove forests! Local fishermen share stories.","choices":[{"text":"🎣 Fish with them","next":"fish","health":0,"xp":70},{"text":"📸 Take photos","next":"end_win","health":0,"xp":50}]},"banana":{"text":"Security won''t let you in without a resident invite!","choices":[{"text":"🤝 Talk your way in","next":"talk","health":0,"xp":40},{"text":"🏝️ Go to Tarkwa","next":"tarkwa","health":0,"xp":20}]},"swim":{"text":"Swimming at sunset. Dolphins spotted in the distance!","choices":[{"text":"🐬 Amazing!","next":"end_win","health":0,"xp":120}]},"horse":{"text":"Galloping along the beach. Pure freedom.","choices":[{"text":"📸 Capture it","next":"end_win","health":0,"xp":130}]},"fish":{"text":"You catch a huge tilapia! Fishermen roast it for you.","choices":[{"text":"🐟 Best meal ever","next":"end_win","health":0,"xp":150}]},"talk":{"text":"You befriend a resident. Private beach, infinity pools!","choices":[{"text":"🏊 VIP vibes","next":"end_win","health":0,"xp":100}]}}'::jsonb, 11),
('tech', '💻 Lagos Tech Scene', 'Launch your startup in Yaba', '#0284c7', 's', '{"s":{"text":"You have a startup idea. Where to begin in Lagos?","choices":[{"text":"🏢 CcHub Yaba","next":"cchub","health":0,"xp":40},{"text":"💰 Find investors","next":"invest","health":0,"xp":20},{"text":"👨‍💻 Build MVP","next":"build","health":0,"xp":30}]},"cchub":{"text":"You join CcHub''s incubator. Free WiFi, mentors, and coffee!","choices":[{"text":"🚀 Pitch to mentors","next":"pitch","health":0,"xp":50},{"text":"👥 Network","next":"network","health":0,"xp":40}]},"invest":{"text":"Angel investor meeting at Radisson Blu. You pitch hard.","choices":[{"text":"💰 They invest!","next":"funded","health":0,"xp":80},{"text":"❌ Rejected","next":"build","health":-10,"xp":20}]},"build":{"text":"3 months coding. You launch on Product Hunt.","choices":[{"text":"🚀 Goes viral","next":"end_win","health":0,"xp":120}]},"pitch":{"text":"Mentors love it! They connect you to Flutterwave''s CTO.","choices":[{"text":"🤝 Partnership","next":"end_win","health":0,"xp":150}]},"network":{"text":"You meet your co-founder at a meetup. Perfect skill match!","choices":[{"text":"🤝 Start building","next":"end_win","health":0,"xp":130}]},"funded":{"text":"₦10 million seed round! You hire your first team.","choices":[{"text":"🚀 Launch!","next":"end_win","health":0,"xp":150}]}}'::jsonb, 12),
('fuel', '⛽ Fuel Scarcity', 'Navigate a Lagos fuel crisis', '#dc2626', 's', '{"s":{"text":"Fuel scarcity! Your car is on E. Stations have 3-hour queues.","choices":[{"text":"⏳ Join queue","next":"queue","health":-20,"xp":20},{"text":"🏍️ Use Okada","next":"okada","health":0,"xp":30},{"text":"🏠 Stay home","next":"home","health":0,"xp":10}]},"queue":{"text":"You''ve been in queue 2 hours. Fight breaks out ahead.","choices":[{"text":"🙏 Stay calm","next":"calm","health":-10,"xp":40},{"text":"🏃 Leave","next":"okada","health":-10,"xp":20}]},"okada":{"text":"Okada gets you to work but costs ₦3000.","choices":[{"text":"💰 Worth it","next":"end_win","health":-10,"xp":60}]},"home":{"text":"Boss calls. ''Where are you?'' No excuse works.","choices":[{"text":"📱 Beg from home","next":"end_lose","health":-20,"xp":10}]},"calm":{"text":"You finally get fuel! Only 10 litres but it''s gold.","choices":[{"text":"⛽ Fill up","next":"end_win","health":0,"xp":100}]}}'::jsonb, 13),
('concert', '🎵 Lagos Concert', 'Attend an Afrobeats show', '#7c3aed', 's', '{"s":{"text":"Burna Boy concert at Eko Convention! Tickets are ₦30K.","choices":[{"text":"🎫 Buy VIP","next":"vip","health":0,"xp":30},{"text":"🎫 Regular ticket","next":"regular","health":0,"xp":20},{"text":"🤝 Sneak in","next":"sneak","health":-20,"xp":40}]},"vip":{"text":"Front row! Burna performs ''Last Last''. Crowd goes wild!","choices":[{"text":"📱 Record everything","next":"record","health":0,"xp":60},{"text":"💃 Just dance","next":"end_win","health":0,"xp":100}]},"regular":{"text":"Far from stage but energy is insane. People lifting each other.","choices":[{"text":"💃 Mosh pit","next":"mosh","health":-10,"xp":50},{"text":"📱 Live tweet","next":"end_win","health":0,"xp":60}]},"sneak":{"text":"Security catches you at the gate!","choices":[{"text":"🏃 Run!","next":"run","health":-20,"xp":30},{"text":"🙏 Beg","next":"end_lose","health":-10,"xp":10}]},"record":{"text":"Burna points at your phone during a song! Video goes viral.","choices":[{"text":"🌟 Famous!","next":"end_win","health":0,"xp":150}]},"mosh":{"text":"Wild night! Your shoes come off but best concert ever.","choices":[{"text":"👟 Worth it","next":"end_win","health":0,"xp":120}]},"run":{"text":"You outrun them and blend into the crowd inside!","choices":[{"text":"💃 Party!","next":"end_win","health":0,"xp":100}]}}'::jsonb, 14),
('danfo', '🚐 Danfo Diaries', 'A wild ride in a Lagos Danfo', '#eab308', 's', '{"s":{"text":"You board a Danfo at Ojuelegba. Conductor shouts ''CMS! CMS!''","choices":[{"text":"💺 Sit by window","next":"window","health":0,"xp":20},{"text":"🧍 Stand at door","next":"door","health":-10,"xp":30}]},"window":{"text":"Breeze is nice until conductor asks for extra ₦50 ''for AC''.","choices":[{"text":"😂 Pay him","next":"pay","health":0,"xp":30},{"text":"😤 Refuse","next":"refuse","health":-10,"xp":20}]},"door":{"text":"You see everything! Street hawkers selling plantain chips, gala, water.","choices":[{"text":"🍌 Buy snacks","next":"snack","health":0,"xp":40},{"text":"🎵 Enjoy the chaos","next":"enjoy","health":0,"xp":30}]},"pay":{"text":"Entire bus laughs. Now everyone calls you ''Chairman''.","choices":[{"text":"😂 Own it","next":"end_win","health":0,"xp":100}]},"refuse":{"text":"Conductor threatens to stop bus. Other passengers intervene.","choices":[{"text":"🤝 Peace made","next":"end_win","health":0,"xp":60}]},"snack":{"text":"Gala + cold La Casera in a Danfo. Peak Lagos experience.","choices":[{"text":"😋 Delicious","next":"end_win","health":0,"xp":120}]},"enjoy":{"text":"Driver''s radio blasts Fela. Sun setting over Third Mainland. Beautiful.","choices":[{"text":"🌅 Lagos magic","next":"end_win","health":0,"xp":130}]}}'::jsonb, 15),
('barber', '💈 Lagos Barber', 'Get the perfect haircut', '#64748b', 's', '{"s":{"text":"You need a fresh cut for an event. Which barber?","choices":[{"text":"💈 Local barber","next":"local","health":0,"xp":20},{"text":"💈 Upscale salon","next":"salon","health":0,"xp":10},{"text":"💈 Street barber","next":"street","health":0,"xp":30}]},"local":{"text":"''How you wan am?'' You show him a Travis Scott photo.","choices":[{"text":"✂️ Trust him","next":"trust","health":0,"xp":50},{"text":"📱 Show more photos","next":"more","health":0,"xp":30}]},"salon":{"text":"₦8000 for a haircut?! But the AC is working...","choices":[{"text":"💰 Pay up","next":"pay","health":0,"xp":40},{"text":"🏃 Leave","next":"street","health":0,"xp":20}]},"street":{"text":"Barber under the bridge has a queue. Clearly the GOAT.","choices":[{"text":"⏳ Wait","next":"trust","health":0,"xp":60}]},"trust":{"text":"He gives you the cleanest fade you''ve ever had. ₦1500!","choices":[{"text":"💰 Tip him","next":"end_win","health":0,"xp":150}]},"more":{"text":"''Bros relax, I go give you better pass this one.'' He delivers!","choices":[{"text":"😍 Perfect","next":"end_win","health":0,"xp":120}]},"pay":{"text":"Smooth cut, hot towel treatment. You look like a million bucks.","choices":[{"text":"💅 Worth it","next":"end_win","health":0,"xp":100}]}}'::jsonb, 16),
('generator', '🔌 Generator Saga', 'Your gen just packed up', '#b45309', 's', '{"s":{"text":"Gen just died. NEPA took light 6 hours ago. It''s 40°C.","choices":[{"text":"🔧 Call mechanic","next":"mech","health":0,"xp":20},{"text":"🏪 Go to mall for AC","next":"mall","health":0,"xp":30},{"text":"🛏️ Sleep it off","next":"sleep","health":-20,"xp":10}]},"mech":{"text":"Mechanic says coil burnt. ₦25,000 to fix.","choices":[{"text":"💰 Fix it","next":"fix","health":0,"xp":40},{"text":"🤝 Negotiate","next":"negotiate","health":0,"xp":50}]},"mall":{"text":"Palms Lekki! Sweet AC. You buy nothing but stay 4 hours.","choices":[{"text":"🛍️ Finally shop","next":"shop","health":0,"xp":60},{"text":"📱 Work from mall","next":"work","health":0,"xp":40}]},"sleep":{"text":"Can''t sleep. Mosquitoes + heat = nightmare combo.","choices":[{"text":"🏪 Go to mall","next":"mall","health":-10,"xp":20}]},"fix":{"text":"Gen roars back! Neighborhood cheers.","choices":[{"text":"⚡ Power!","next":"end_win","health":0,"xp":100}]},"negotiate":{"text":"₦18K final price. He fixes it in 20 min. Legend.","choices":[{"text":"⚡ Power!","next":"end_win","health":0,"xp":130}]},"shop":{"text":"You discover a solar panel shop. Future-proof solution!","choices":[{"text":"☀️ Go solar","next":"end_win","health":0,"xp":150}]},"work":{"text":"Most productive day ever. Free WiFi + AC = focus mode.","choices":[{"text":"💪 Done!","next":"end_win","health":0,"xp":100}]}}'::jsonb, 17),
('food', '🍲 Food Tour', 'Explore Lagos street food scene', '#16a34a', 's', '{"s":{"text":"You''re doing a Lagos food tour. Start where?","choices":[{"text":"🍳 Agege bread spot","next":"agege","health":0,"xp":30},{"text":"🫘 Ewa Agoyin mama","next":"ewa","health":0,"xp":40},{"text":"🥘 Amala joint","next":"amala","health":0,"xp":30}]},"agege":{"text":"Hot Agege bread with ewa agoyin. Butter melting on top.","choices":[{"text":"😋 Second helping","next":"second","health":0,"xp":50},{"text":"🫘 Try Ewa next","next":"ewa","health":0,"xp":30}]},"ewa":{"text":"Mama''s ewa with dodo and fish! Perfectly peppered.","choices":[{"text":"🔥 More pepper","next":"pepper","health":0,"xp":40},{"text":"🥘 Head to Amala","next":"amala","health":0,"xp":30}]},"amala":{"text":"Abula spot in Ogba. Amala + ewedu + gbegiri + assorted.","choices":[{"text":"🥘 Demolish it","next":"demolish","health":0,"xp":60}]},"second":{"text":"Third helping! Fellow eaters nod in respect.","choices":[{"text":"🤝 Share with stranger","next":"end_win","health":0,"xp":120}]},"pepper":{"text":"Eyes watering. Stomach on fire. But you can''t stop!","choices":[{"text":"🥵 Worth it","next":"end_win","health":0,"xp":100}]},"demolish":{"text":"You finish everything. Mama gives you extra meat. ''Fine boy!''","choices":[{"text":"😊 Best meal ever","next":"end_win","health":0,"xp":150}]}}'::jsonb, 18);
INSERT INTO cms_wordgame (word_id, word, clue, category, image, description, history, footnotes, sort_order) VALUES
('gw-01', 'BADAGRY', 'Coastal town with a dark slave trade history', 'Place', '/images/postcards/badagry.png', 'Badagry is a coastal town in Lagos State, situated between Lagos and Seme on the border with Benin Republic. It was one of the most active slave ports in West Africa from the 16th to 19th century.', '["Founded in the early 15th century by the Egun people who migrated from modern-day Togo and Benin.","Between 1518 and 1840, Badagry served as a major slave port — an estimated 550,000 Africans were shipped through its shores to the Americas.¹","The \"Point of No Return\" at Gberefu Island marks where enslaved people boarded ships, never to see Africa again.","The first Christian missionary in Nigeria, Rev. Thomas Birch Freeman, arrived in Badagry on September 24, 1842.²","The first storey building in Nigeria was built here in 1845 by the CMS missionaries — it still stands today as a heritage site.","Badagry is home to the Heritage Museum, the Slave Market relics, and Vlekete Slave Market — the oldest in West Africa."]'::jsonb, '["¹ UNESCO Slave Route Project, \"Badagry Heritage Sites Documentation,\" 2006.","² Ajayi, J.F.A., Christian Missions in Nigeria 1841-1891, Northwestern University Press, 1965."]'::jsonb, 0),
('gw-02', 'BENIN', 'Ancient kingdom famous for bronze art', 'Kingdom', NULL, 'The Kingdom of Benin (not to be confused with the modern Republic of Benin) was one of the most powerful and technologically advanced civilizations in pre-colonial Africa, centered in present-day Edo State, Nigeria.', '["Founded around 900 AD by the Edo people, the kingdom reached its peak under Oba Ewuare the Great (c. 1440–1473) who rebuilt the capital and established a centralized government.¹","Benin City was one of the first cities in the world to have street lighting — palm oil lamps lined the streets as early as the 13th century.","The famous Benin Bronzes — over 4,000 brass and bronze plaques and sculptures — are among the finest examples of metalwork in human history.²","The city walls of Benin (Iya) were the largest earthwork in the world pre-mechanisation — four times longer than the Great Wall of China and consumed 100 times more material than the Great Pyramid of Giza.³","In 1897, British forces invaded and looted the kingdom in the \"Punitive Expedition,\" stealing thousands of artworks now held in Western museums.","Nigeria has been actively pursuing the repatriation of the Benin Bronzes. Germany returned over 1,100 pieces in 2022."]'::jsonb, '["¹ Egharevba, J.U., A Short History of Benin, Ibadan University Press, 1968.","² Plankensteiner, B., Benin Kings and Rituals: Court Arts from Nigeria, Kunsthistorisches Museum, 2007.","³ Darling, P.J., \"Archaeology and History in Southern Nigeria,\" Cambridge Monographs in African Archaeology, 1984."]'::jsonb, 1),
('gw-03', 'SOYINKA', 'First African Nobel Literature laureate', 'Person', NULL, 'Wole Soyinka (born Akinwande Oluwole Babatunde Soyinka on July 13, 1934) is a Nigerian playwright, poet, and essayist. He became the first African to win the Nobel Prize in Literature in 1986.', '["Born in Abeokuta, Ogun State, Soyinka studied at the University of Ibadan and the University of Leeds in England.¹","His plays, including \"A Dance of the Forests\" (1960), \"The Lion and the Jewel\" (1963), and \"Death and the King''s Horseman\" (1975), blend Yoruba mythology with modernist drama.","During the Nigerian Civil War, he was imprisoned for two years (1967-1969) by the Gowon regime for trying to broker peace with Biafra.²","His prison memoir \"The Man Died\" (1972) is considered one of the most powerful accounts of political imprisonment in Africa.","He was awarded the Nobel Prize in Literature in 1986 \"who in a wide cultural perspective and with poetic overtones fashions the drama of existence.\"³","Soyinka has been a vocal critic of military dictatorship in Nigeria, living in exile during the Abacha regime (1994-1998)."]'::jsonb, '["¹ Jeyifo, B., Wole Soyinka: Politics, Poetics and Postcolonialism, Cambridge University Press, 2004.","² Soyinka, W., The Man Died: Prison Notes, Rex Collings, 1972.","³ The Nobel Foundation, \"Press Release: The Nobel Prize in Literature 1986,\" October 16, 1986."]'::jsonb, 2),
('gw-04', 'CALABAR', 'City known for its famous December carnival', 'Place', NULL, 'Calabar is the capital of Cross River State in southeastern Nigeria. Known as "Canaan City" or the "Paradise City," it is one of the cleanest and most tourism-friendly cities in Nigeria.', '["Originally called \"Akwa Akpa\" by the Efik people, the name \"Calabar\" was given by Portuguese and Spanish traders who arrived in the 15th century.¹","It served as the first capital of the Southern Nigeria Protectorate from 1906 until the capital moved to Lagos in 1914.","Mary Slessor, a Scottish missionary, lived here from 1876 and fought to end the killing of twin babies — a practice rooted in local superstition.²","The Calabar Carnival (Africa''s Biggest Street Party) was established in 2004 and attracts over 2 million visitors every December.","The Slave History Museum at the Marina Resort documents Calabar''s role in the transatlantic slave trade.","Cross River National Park, near Calabar, is home to the endangered Cross River gorilla — the rarest great ape in the world."]'::jsonb, '["¹ Latham, A.J.H., Old Calabar 1600-1891, Oxford University Press, 1973.","² Livingstone, W.P., Mary Slessor of Calabar: Pioneer Missionary, Hodder and Stoughton, 1916."]'::jsonb, 3),
('gw-05', 'ACHEBE', 'Author of "Things Fall Apart"', 'Person', NULL, 'Chinua Achebe (November 16, 1930 – March 21, 2013) was a Nigerian novelist, poet, and critic, widely regarded as the father of modern African literature.', '["Born Albert Chinualumogu Achebe in Ogidi, Anambra State, to an Igbo family of the Church Missionary Society.¹","\"Things Fall Apart\" (1958), his debut novel, has sold over 20 million copies and been translated into 57 languages — making it the most widely read book in modern African literature.²","The novel challenged Western portrayals of Africa, particularly Joseph Conrad''s \"Heart of Darkness,\" which Achebe called \"an offensive and deplorable book.\"","He served as a diplomat for Biafra during the Nigerian Civil War (1967-1970) and documented the war''s horrors.","Achebe twice declined the Nigerian national honour of Commander of the Federal Republic (CFR) in 2004 and 2011, citing political corruption.","His other major works include \"No Longer at Ease\" (1960), \"Arrow of God\" (1964), and \"Anthills of the Savannah\" (1987)."]'::jsonb, '["¹ Ezenwa-Ohaeto, Chinua Achebe: A Biography, Indiana University Press, 1997.","² Irele, F.A., \"The Crisis of Cultural Memory in Chinua Achebe''s Things Fall Apart,\" African Studies Quarterly, 2000."]'::jsonb, 4),
('gw-06', 'LAGOS', 'Megacity and economic capital of Nigeria', 'Place', NULL, 'Lagos is the largest city in Africa by population (estimated 16-24 million) and the economic hub of Nigeria, generating over 30% of the country''s GDP.', '["Originally called \"Eko\" by its Awori founders, Portuguese explorer Ruy de Sequeira renamed it \"Lagos\" (meaning \"lakes\") in 1472.¹","Lagos served as the capital of Nigeria from 1914 until 1991 when the capital was moved to Abuja.","The city was a major slave trading port — Tinubu Square is named after Madam Efunroye Tinubu, a powerful 19th-century slave trader and political figure.²","Lagos Island was connected to the mainland via Carter Bridge in 1901 — Nigeria''s first bridge.","Today Lagos is home to Africa''s largest film industry (Nollywood), the continent''s busiest port (Apapa), and the emerging tech hub of Yaba — dubbed \"Yabacon Valley.\"","The Dangote Refinery in Lekki Free Trade Zone, opened in 2024, is the world''s largest single-train petroleum refinery with 650,000 barrels/day capacity."]'::jsonb, '["¹ Aderibigbe, A.B., Lagos: The Development of an African City, Longman, 1975.","² Mann, K., Slavery and the Birth of an African City: Lagos, 1760-1900, Indiana University Press, 2007."]'::jsonb, 5),
('gw-07', 'FELA', 'Pioneer of Afrobeat music', 'Person', NULL, 'Fela Anikulapo Kuti (October 15, 1938 – August 2, 1997) was a Nigerian musician, bandleader, and political activist who created the Afrobeat genre — a fusion of jazz, funk, highlife, and Yoruba rhythms.', '["Born Olufela Olusegun Oludotun Ransome-Kuti in Abeokuta to a prominent family — his mother, Funmilayo Ransome-Kuti, was a feminist pioneer and anti-colonial activist.¹","He changed his middle name from \"Ransome-Kuti\" to \"Anikulapo\" (meaning \"he who carries death in his pouch\") in 1975 to reject his colonial surname.","His commune, the Kalakuta Republic, was raided by 1,000 Nigerian soldiers in 1977. His mother was thrown from a window and later died from her injuries.²","Fela married 27 women on the same day in 1978, partly as a political statement and partly to protect them from government harassment.","He recorded over 50 albums, with songs like \"Zombie\" (1977) directly attacking the Nigerian military — it sold over 100,000 copies in its first week.","Fela died on August 2, 1997 from AIDS-related complications. Over one million people attended his funeral procession through Lagos."]'::jsonb, '["¹ Veal, M.E., Fela: The Life and Times of an African Musical Icon, Temple University Press, 2000.","² Moore, C., Fela: This Bitch of a Life, Allison & Busby, 1982."]'::jsonb, 6),
('gw-08', 'ABUJA', 'Capital city built from scratch in the 1980s', 'Place', '/images/postcards/aso-rock.png', 'Abuja is the capital city of Nigeria, located in the Federal Capital Territory (FCT) in central Nigeria. It was purpose-built to replace Lagos as the capital.', '["The decision to move the capital from Lagos was made in 1976 under General Murtala Mohammed, and the Aguda Panel recommended the current site.¹","The city was master-planned by International Planning Associates (IPA), a consortium led by American architect-planner Wallace McHarg Roberts & Todd.","Abuja officially became the capital on December 12, 1991, under President Ibrahim Babangida.","The city is dominated by Aso Rock, a 400-meter monolith that houses the Presidential Villa, National Assembly, and Supreme Court.","The Abuja National Mosque and National Christian Centre face each other on opposite sides of Independence Avenue — symbolizing religious coexistence.","The city''s population has grown from under 100,000 in 1991 to an estimated 3.6 million today, making it one of the fastest-growing cities in Africa."]'::jsonb, '["¹ Elleh, N., Abuja: The Single Most Ambitious Urban Design Project of the 20th Century, Weaver Press, 2001."]'::jsonb, 7),
('gw-09', 'OSOGBO', 'City with a UNESCO Sacred Grove', 'Place', '/images/postcards/osun-grove.png', 'Osogbo (also Oshogbo) is the capital of Osun State in southwestern Nigeria, renowned for the Osun-Osogbo Sacred Grove — a UNESCO World Heritage Site since 2005.', '["According to legend, Osogbo was founded when the hunter Olutimehin and his people discovered the Osun River. The river goddess Osun permitted them to settle if they maintained her sacred grove.¹","The Osun-Osogbo Sacred Grove is one of the last remnants of primary high forest in southern Nigeria, covering 75 hectares along the Osun River.","Austrian artist Suzanne Wenger (Adunni Olorisa) spent 50 years (1958-2009) in Osogbo, creating monumental sculptures within the grove.²","The annual Osun-Osogbo Festival, held every August, attracts hundreds of thousands of worshippers and tourists from around the world.","Osogbo is also a center of batik art — the Osogbo Art Movement of the 1960s, led by Ulli Beier and Georgina Beier, trained local artists who became internationally renowned."]'::jsonb, '["¹ Abimbola, W., \"The Bag of Wisdom: Osun and the Origins of Ifa Divination,\" Odu: Journal of Yoruba Studies, 1997.","² Probst, P., Osogbo and the Art of Heritage: Monuments, Deities, and Money, Indiana University Press, 2011."]'::jsonb, 8),
('gw-10', 'KANO', 'Ancient city and commercial hub of Northern Nigeria', 'Place', NULL, 'Kano is the largest city in Northern Nigeria and the second-largest city in the country. It has been a major center of trade, Islamic scholarship, and culture for over 1,000 years.', '["Founded around 999 AD by Bagauda, the first king of Kano, according to the Kano Chronicle.¹","By the 15th century, Kano was one of the Hausa city-states and a major terminus of trans-Saharan trade routes, trading gold, leather, and textiles.","The city walls (Ganuwar Kano), originally built in the 12th century, stretch 14 km and still partially stand today.","Kano was conquered by Usman dan Fodio during the Fulani jihad of 1807 and became part of the Sokoto Caliphate.²","The Kano Dye Pits (Kofar Mata) have been in continuous use for over 500 years — they are the oldest dye pits in Africa, producing the famous \"Kano indigo.\"","Today Kano is Nigeria''s industrial center for textiles, tanning, and groundnut processing, with the Dawanau Market being the largest grain market in Africa."]'::jsonb, '["¹ Palmer, H.R., \"The Kano Chronicle,\" Journal of the Royal Anthropological Institute, 1908.","² Last, M., The Sokoto Caliphate, Longmans, 1967."]'::jsonb, 9),
('gw-11', 'BIAFRA', 'Secessionist state of the 1967-1970 civil war', 'Event', NULL, 'The Republic of Biafra was a secessionist state in southeastern Nigeria that existed from May 30, 1967 to January 15, 1970, during the Nigerian Civil War.', '["Following anti-Igbo pogroms in Northern Nigeria in 1966 that killed an estimated 30,000-50,000 people, the Eastern Region under Lt. Col. Odumegwu Ojukwu declared independence as \"Biafra.\"¹","The Nigerian federal government under General Yakubu Gowon imposed a land and sea blockade, leading to mass starvation.","An estimated 1-3 million Biafrans died, mostly from famine — the images of starving children shocked the world and helped create the modern humanitarian aid movement.²","Biafra had its own currency, flag, and international recognition from five countries including Tanzania, Gabon, and Côte d''Ivoire.","The war ended on January 15, 1970, when Biafra surrendered. Gowon declared \"No victor, no vanquished\" — a policy of reconciliation.","The war inspired the establishment of Médecins Sans Frontières (Doctors Without Borders) in 1971 by French doctors who had worked in Biafra.³"]'::jsonb, '["¹ Achebe, C., There Was a Country: A Personal History of Biafra, Penguin Press, 2012.","² De St. Jorre, J., The Brothers'' War: Biafra and Nigeria, Faber & Faber, 1972.","³ Taithe, B., \"Reinventing (French) Universalism: Religion, Humanitarianism and the French Doctors,\" Modern & Contemporary France, 2004."]'::jsonb, 10),
('gw-12', 'JOLLOF', 'The most debated rice dish in West Africa', 'Culture', NULL, 'Jollof rice is a one-pot rice dish cooked in a tomato-based sauce, widely considered the most iconic food in West African cuisine — and the subject of fierce rivalry between Nigeria and Ghana.', '["The dish originated from the Wolof people of the Senegambia region (14th century Jolof Empire), where it was called \"thiéboudienne\" or \"benachin.\"¹","As the recipe spread across West Africa through trade and migration, each country developed its own version — Nigerian jollof uses long-grain rice and smoky flavors.","The \"Jollof Wars\" — an ongoing social media debate between Nigeria and Ghana over who makes the best jollof — has become one of the most viral food debates on the internet.²","In 2014, Ghanaian musician Sister Deborah released \"Ghana Jollof,\" escalating the rivalry. Nigerian Twitter responded with memes and cooking videos.","Jollof rice is a staple at every Nigerian celebration — weddings, naming ceremonies, and parties. \"Party jollof\" (cooked in large quantities over firewood) is considered superior to home-cooked versions.","In 2021, Jollof rice was officially recognized by UNESCO as an intangible cultural heritage food of West Africa."]'::jsonb, '["¹ Osseo-Asare, F., Food Culture in Sub-Saharan Africa, Greenwood Press, 2005.","² Farinde, D., \"The Politics of Jollof: Food, Identity, and Social Media in West Africa,\" Journal of African Cultural Studies, 2019."]'::jsonb, 11);
INSERT INTO cms_postcards (postcard_id, pack, image, question, options, correct_index, category, fact, sort_order) VALUES
('vg-01', 'visual', '/images/postcards/national-theatre.png', 'Which iconic Lagos building is shown in this postcard?', '["National Theatre","Eko Hotel","MUSON Centre","Federal Secretariat"]'::jsonb, 0, 'visual', 'The National Theatre was built in 1976 for FESTAC 77 and is shaped like a military hat.', 0),
('vg-02', 'visual', '/images/postcards/third-mainland-bridge.png', 'This bridge connects Lagos Island to the mainland. What is it?', '["Carter Bridge","Eko Bridge","Third Mainland Bridge","Lekki-Ikoyi Link Bridge"]'::jsonb, 2, 'visual', 'Third Mainland Bridge is 11.8 km long — the longest bridge in Africa when it opened in 1990.', 1),
('vg-03', 'visual', '/images/postcards/zuma-rock.png', 'This massive monolith sits along the Abuja–Kaduna highway. Name it.', '["Olumo Rock","Zuma Rock","Aso Rock","Idanre Hills"]'::jsonb, 1, 'visual', 'Zuma Rock is 725m high and appears on the ₦100 note. Locals call it "Gateway to Abuja".', 2),
('vg-04', 'visual', '/images/postcards/olumo-rock.png', 'This ancient rock fortress is located in Abeokuta. What is it?', '["Zuma Rock","Ikogosi Warm Springs","Olumo Rock","Erin-Ijesha Falls"]'::jsonb, 2, 'visual', 'Olumo Rock served as a natural fortress during inter-tribal wars in the 19th century.', 3),
('vg-05', 'visual', '/images/postcards/lekki-ikoyi-bridge.png', 'This cable-stayed bridge connects Lekki Phase 1 to Ikoyi. Name it.', '["Third Mainland Bridge","Lekki-Ikoyi Link Bridge","Carter Bridge","Falomo Bridge"]'::jsonb, 1, 'visual', 'The bridge was completed in 2013 and its LED lights change colors at night.', 4),
('vg-06', 'visual', '/images/postcards/badagry.png', 'This coastal town is known as the "point of no return" in the slave trade.', '["Epe","Badagry","Ikorodu","Ajegunle"]'::jsonb, 1, 'visual', 'Badagry has the first two-storey building in Nigeria, built by missionaries in 1845.', 5),
('vg-07', 'visual', '/images/postcards/tafawa-balewa.png', 'This open square on Lagos Island hosted Nigeria''s independence ceremony.', '["Eagle Square","Tafawa Balewa Square","Tinubu Square","Freedom Park"]'::jsonb, 1, 'visual', 'TBS is named after Nigeria''s first Prime Minister and can hold 18,000 people.', 6),
('vg-08', 'visual', '/images/postcards/abuja-mosque.png', 'This mosque is one of the most prominent landmarks in Nigeria''s capital.', '["Kano Central Mosque","Lagos Central Mosque","Abuja National Mosque","Ibadan Grand Mosque"]'::jsonb, 2, 'visual', 'The Abuja National Mosque can accommodate over 15,000 worshippers.', 7),
('vg-09', 'visual', '/images/postcards/nike-art-gallery.png', 'This is the largest art gallery in West Africa, located in Lekki.', '["Didi Museum","Terra Kulture","Nike Art Gallery","Wheatbaker Gallery"]'::jsonb, 2, 'visual', 'Nike Art Gallery has over 8,000 artworks across 5 floors.', 8),
('vg-10', 'visual', '/images/postcards/aso-rock.png', 'This iconic rock formation houses the Nigerian Presidential Complex.', '["Zuma Rock","Olumo Rock","Aso Rock","Idanre Hills"]'::jsonb, 2, 'visual', 'Aso Rock is 400m high and means "victorious people" in the Asokoro dialect.', 9),
('vg-11', 'visual', '/images/postcards/osun-grove.png', 'This UNESCO World Heritage Site is a sacred forest in Osun State.', '["Yankari Reserve","Osun-Osogbo Sacred Grove","Cross River Park","Lekki Conservation"]'::jsonb, 1, 'visual', 'The grove is one of the last remnants of primary high forest in southern Nigeria.', 10),
('vg-12', 'visual', '/images/postcards/unilag.png', 'This university campus sits on the lagoon front in Akoka.', '["LASU","University of Lagos","Lagos State Polytechnic","Yaba College of Tech"]'::jsonb, 1, 'visual', 'UNILAG was founded in 1962 — "University of first choice and the nation''s pride".', 11),
('vg-13', 'visual', '/images/postcards/balogun-market.png', 'This is the largest open-air market on Lagos Island. Name it.', '["Balogun Market","Oshodi Market","Mile 12 Market","Alaba International"]'::jsonb, 0, 'visual', 'Balogun Market generates an estimated ₦2 billion daily in trade — it''s the commercial heart of Lagos Island.', 12),
('vg-14', 'visual', '/images/postcards/danfo-bus.png', 'What are these iconic yellow commercial buses called in Lagos?', '["Keke","Danfo","BRT","Molue"]'::jsonb, 1, 'visual', 'Danfo buses are Volkswagen T3 vans painted yellow. They carry over 10 million Lagosians daily and are being gradually phased out for BRT buses.', 13),
('vg-15', 'visual', '/images/postcards/makoko.png', 'This famous waterfront community is sometimes called "Venice of Africa."', '["Ilaje","Makoko","Ajegunle","Bariga"]'::jsonb, 1, 'visual', 'Makoko houses over 250,000 people on stilts above the Lagos Lagoon. The Makoko Floating School (2013) by Kunlé Adeyemi gained global acclaim.', 14),
('vg-16', 'visual', '/images/postcards/computer-village.png', 'This is the largest technology market in Africa. Where is it?', '["Alaba International","Computer Village, Ikeja","Trade Fair Complex","Ladipo Market"]'::jsonb, 1, 'visual', 'Computer Village generates ₦1.5 billion daily in tech trade. Over 5,000 shops sell phones, laptops, and accessories.', 15),
('vg-17', 'visual', '/images/postcards/egungun-festival.png', 'What Yoruba masquerade festival is shown in this image?', '["Gelede","Egungun Festival","Osun Festival","New Yam Festival"]'::jsonb, 1, 'visual', 'Egungun masquerades represent ancestral spirits. The elaborate costumes can weigh over 50 kg and twirl at incredible speeds.', 16),
('ck-01', 'cultural', '/images/postcards/balogun-market.png', '"Omo, see as this thing set!" — Which LGA popularized this slang style?', '["Ajeromi-Ifelodun","Surulere","Ikeja","Eti-Osa"]'::jsonb, 0, 'cultural', '"Omo" (child) became universal Lagos slang from the Ajegunle/Ajeromi melting pot — Igbo, Yoruba, Ijaw cultures mixed to create a unique street pidgin.', 17),
('ck-02', 'cultural', '/images/postcards/egungun-festival.png', 'The "Eyo Festival" is unique to which city?', '["Ibadan","Abeokuta","Lagos","Benin City"]'::jsonb, 2, 'cultural', 'The Eyo Festival (Adamu Orisha) features white-robed masquerades parading through Lagos Island. It dates back to the early 1800s and honors deceased Lagos chiefs.', 18),
('ck-03', 'cultural', '/images/postcards/badagry.png', 'Which food originated from the Yoruba/Brazilian returnee culture?', '["Jollof Rice","Agege Bread","Puff-Puff","Boli"]'::jsonb, 2, 'cultural', 'Puff-puff descended from Portuguese "filhós" brought by Brazilian-Yoruba returnees (Aguda) who settled in Badagry and Lagos Island in the 1800s.', 19),
('ck-04', 'cultural', '/images/postcards/national-theatre.png', 'FESTAC 77 was the largest cultural festival in African history. What does FESTAC stand for?', '["Federal State Arts Council","Festival of Arts & Culture","Federation of State Arts & Culture","Festival of African Culture"]'::jsonb, 1, 'cultural', 'FESTAC 77 (2nd World Black & African Festival of Arts & Culture) attracted 17,000 participants from 59 countries. Stevie Wonder and Miriam Makeba performed.', 20),
('ck-05', 'cultural', '/images/postcards/computer-village.png', '"Whatsapp me the address" was first adopted widely in Nigeria in what year?', '["2010","2012","2014","2016"]'::jsonb, 1, 'cultural', 'Nigeria became WhatsApp''s fastest-growing market in 2012. Computer Village Ikeja was the hub where phones were "flashed" (unlocked) to run the app.', 21),
('ck-06', 'cultural', '/images/postcards/makoko.png', 'Which slang means "no money" in Lagos pidgin?', '["\"I dey kampe\"","\"Pocket dey cry\"","\"E choke\"","\"Wahala dey\""]'::jsonb, 1, 'cultural', '"Pocket dey cry" emerged from the Makoko/Ajegunle waterfront communities where daily earnings from fishing could be as low as ₦500 ($0.50).', 22),
('ck-07', 'cultural', '/images/postcards/olumo-rock.png', 'The Lisabi Festival celebrates which historical event?', '["Founding of Lagos","Egba liberation from Oyo","Fall of Benin Empire","Biafra independence"]'::jsonb, 1, 'cultural', 'Lisabi Agbongbo Akala led the Egba revolt against the Oyo Empire around 1775. The festival in Abeokuta celebrates this liberation every year.', 23),
('ck-08', 'cultural', '/images/postcards/third-mainland-bridge.png', 'What is "Agege Bread" traditionally shaped like?', '["Round flat disc","Long baguette","Tall rectangular loaf","Small round ball"]'::jsonb, 2, 'cultural', 'Agege Bread is a soft, dense rectangular loaf named after the Agege area of Lagos. It''s often paired with ewa agoyin (mashed beans) for the iconic street breakfast.', 24),
('ck-09', 'cultural', '/images/postcards/tafawa-balewa.png', 'The "Ojude Oba" festival is celebrated in which city?', '["Lagos","Abeokuta","Ijebu-Ode","Osogbo"]'::jsonb, 2, 'cultural', 'Ojude Oba ("Before the King''s Courtyard") is held in Ijebu-Ode during Eid-el-Kabir. Age groups (Regberegbe) parade in elaborate traditional attire on horseback.', 25),
('ck-10', 'cultural', '/images/postcards/nike-art-gallery.png', 'Which art movement emerged from Osogbo in the 1960s?', '["Afrofuturism","Nsukka School","Osogbo Art Movement","Zaria Art Society"]'::jsonb, 2, 'cultural', 'The Osogbo Art Movement (1962) was initiated by Ulli and Georgina Beier, training local artists like Twins Seven-Seven and Jimoh Buraimoh who gained global fame.', 26),
('hl-01', 'hyperlocal', '/images/postcards/danfo-bus.png', '"Under Bridge" is a famous bus stop in Lagos. Which bridge?', '["Third Mainland","Eko Bridge","Costain Flyover","Ojuelegba Bridge"]'::jsonb, 3, 'hyperlocal', 'The Ojuelegba bridge/underpass is the crossroads of Lagos mainland — Surulere, Yaba, and Mushin converge here. Wizkid''s hit "Ojuelegba" made it globally known.', 27),
('hl-02', 'hyperlocal', '/images/postcards/balogun-market.png', 'Which market is known as the "Phones Graveyard" — where stolen phones end up?', '["Balogun Market","Computer Village","Ladipo Market","Ikeja Under Bridge"]'::jsonb, 2, 'hyperlocal', 'Ladipo Market in Mushin is notorious for selling refurbished and "questionable" phones and auto parts. It spans over 20 acres.', 28),
('hl-03', 'hyperlocal', '/images/postcards/third-mainland-bridge.png', '"CMS" bus stop is named after which organization?', '["Central Motor Services","Church Missionary Society","City Municipal Services","Central Market Street"]'::jsonb, 1, 'hyperlocal', 'CMS = Church Missionary Society, established in Lagos in 1842. The bus stop at the Marina marks where the first Anglican missionaries landed.', 29),
('hl-04', 'hyperlocal', '/images/postcards/computer-village.png', 'What is "Agbado" known for among Lagos commuters?', '["Last affordable bus stop","Fastest BRT route","The end of Lagos","Cheapest fuel station"]'::jsonb, 2, 'hyperlocal', '"Agbado is the end of Lagos" is a running joke. Located at the extreme end of the LAMATA rail line, it marks where Lagos meets Ogun State.', 30),
('hl-05', 'hyperlocal', '/images/postcards/makoko.png', 'Which hidden beach is only accessible by boat from the Lagos harbour?', '["Elegushi Beach","Tarkwa Bay","Lekki Beach","Oniru Beach"]'::jsonb, 1, 'hyperlocal', 'Tarkwa Bay is a sheltered beach near the harbour breakwater. It has a small fishing/surfing community and no road access — boats only from Maroko jetty.', 31),
('hl-06', 'hyperlocal', '/images/postcards/danfo-bus.png', '"Oshodi" was once famously described as what?', '["The cleanest place in Lagos","The most dangerous bus stop in Africa","The birthplace of Afrobeats","The only 24-hour market"]'::jsonb, 1, 'hyperlocal', 'Before the 2009 cleanup by Governor Fashola, Oshodi was a chaotic transit hub with over 500,000 daily commuters, rampant crime, and gridlocked traffic across 6 lanes.', 32),
('hl-07', 'hyperlocal', '/images/postcards/balogun-market.png', 'Which market specializes in second-hand clothes called "Okrika"?', '["Balogun Market","Yaba Market","Katangua Market, Sabo","Eko Idumota"]'::jsonb, 2, 'hyperlocal', 'Katangua Market in Sabo, Yaba is Lagos'' largest thrift market. "Okrika" (bend-down-select) clothes arrive in bales from the UK, US, and Europe.', 33),
('hl-08', 'hyperlocal', '/images/postcards/lekki-ikoyi-bridge.png', 'The "Falomo Roundabout" is a landmark junction in which area?', '["Surulere","Victoria Island","Ikoyi","Yaba"]'::jsonb, 2, 'hyperlocal', 'Falomo is the gateway between Ikoyi and VI. The iconic roundabout near the Falomo bridge sees over 100,000 vehicles daily. The overhead bridge was demolished in 2023.', 34),
('hl-09', 'hyperlocal', '/images/postcards/national-theatre.png', 'What is the popular name for the Mile 2 — Oshodi bus corridor?', '["The Expressway","The Lagos Autobahn","Oshodi-Apapa","The Go-Slow Highway"]'::jsonb, 3, 'hyperlocal', 'The Oshodi-Apapa Expressway is nicknamed "Go-Slow Highway" because traffic can turn a 20-minute drive into 3+ hours, especially near the Tin Can port.', 35),
('hl-10', 'hyperlocal', '/images/postcards/aso-rock.png', 'In Abuja, "Area One" is famous for what?', '["Government offices","Night markets & street food","Military barracks","The zoo"]'::jsonb, 1, 'hyperlocal', 'Abuja''s Area One is the go-to for night owls — suya spots, shawarma stands, and open-air bars line Ahmadu Bello Way after dark. It''s the closest thing to Lagos nightlife in Abuja.', 36);
